SELECT * FROM(
    SELECT @RN:=@RN+1 AS rnum, a.* FROM( 
        SELECT * From Board
        WHERE `DELETE` = 0 

            AND Subject = #{subject}

        ORDER BY PostNum DESC
        ) a, (SELECT @RN:=0) b 
        ) c WHERE c.rnum BETWEEN #{begin} AND #{end}

mapper.update:
UPDATE Board SET Subject = #{subject}, Content = #{content}, ModDate = NOW()
,FileName = #{FileName}
WHERE PostNum = #{PostNum}

UPDATE Board
SET ThumbsUp = ThumbsUp + 1
WHERE PostNum = #{PostNum}

UPDATE Board
SET ThumbsDown = ThumbsDown + 1
WHERE PostNum = #{PostNum}
